+    for (possibilities) |p| {
+        var sm = SequenceMatcher(u8).init(allocator, word, p);
+        defer sm.deinit();
+        const score = try sm.ratio();
+        if (score >= cutoff) {
+            try results.append(.{ .score = score, .word = p });
+        }
