+            .LONG_BINGET, .LONG_BINPUT => {
+                if (pos + 4 <= pickle.len) {
+                    const val = std.mem.readInt(u32, pickle[pos..][0..4], .little);
+                    const arg_str = std.fmt.bufPrint(&buf, " {d}", .{val}) catch "";
+                    try writer.writeAll(arg_str);
